(()=>{'use strict';
const APP_VERSION='Solomon DOIT Pro V2.9.0';
const T=v=>String(v??'').trim();
const N=v=>Number(String(v??'').replace(/,/g,''))||0;
const $=s=>document.querySelector(s);
let rawPayload=null,rawRows=[],meta={},patched=false;
function rowsOf(p){return p?.rows||p||[]}
function cleanPs(v){const parts=T(v).split(/\s+/).filter(Boolean);if(!parts.length)return'';if(parts.length===2&&parts[0]===parts[1])return parts[0];const out=[];parts.forEach(x=>{if(!out.includes(x))out.push(x)});return out.join(' ')}
function appKey(){return T(meta.id||meta.version_id||rawPayload?.version_id||meta.file_name||'active')}
function keys(prefix){const out=[];for(let i=0;i<localStorage.length;i++){const k=localStorage.key(i)||'';if(k.startsWith(prefix))out.push(k)}return out}
function manualKey(){const k=appKey();const existing=keys('doit-manual-v1:');if(k&&k!=='active')return 'doit-manual-v1:'+k;if(existing.length)return existing[0];const sk=keys('doit-json:')[0];return sk?'doit-manual-v1:'+sk.replace(/^doit-json:/,''):'doit-manual-v1:'+k}
function read(k,d){try{return JSON.parse(localStorage.getItem(k)||'')||d}catch{return d}}
function write(k,v){localStorage.setItem(k,JSON.stringify(v))}
function dates(){return[...new Set(rawRows.map(r=>T(r.date)).filter(Boolean))].sort()}
function selectedDates(){return[...new Set((window.DOIT_SELECTED_DATES||[]).map(T).filter(Boolean))].sort()}
function selectedPs(){return[...new Set((window.DOIT_SELECTED_PS_LIST||[]).map(cleanPs).filter(Boolean))].sort((a,b)=>a.localeCompare(b,'th'))}
function getScope(){return{dates:selectedDates(),dateKey:T(window.DOIT_SELECTED_DATE_KEY),ps:selectedPs(),psKey:T(window.DOIT_SELECTED_PS_KEY),receiver:T($('#storeSelect')?.value),brand:T($('#brandSelect')?.value),type:T($('#typeSelect')?.value),q:T($('#q')?.value)}}
function setMsg(s){const m=$('#msg');if(m)m.textContent=s}
function lockTitle(){try{document.title=APP_VERSION}catch{}const t=document.querySelector('.title');if(t)t.textContent=APP_VERSION;const f=document.querySelector('footer');if(f&&/Solomon DOIT Pro/i.test(f.textContent||''))f.textContent=APP_VERSION}
function patchLoad(){const app=window.DOIT_JSON_APP;if(!app||app.__appCoordinator290)return false;const old=app.load.bind(app);app.load=(payload,m={})=>{rawPayload=payload;meta=m||{};const arr=rowsOf(payload);if(Array.isArray(arr)&&arr.length){rawRows=arr;window.__doitRawRows290=arr;window.DOIT_ALL_DATES=dates();window.DOIT_AVAILABLE_DATES=window.DOIT_ALL_DATES}const res=old(payload,m);setTimeout(syncUi,0);setTimeout(syncUi,250);return res};app.__appCoordinator290=true;patched=true;return true}
function syncUi(){lockTitle();const ds=selectedDates();const p=$('#datePreview');if(p){if(!ds.length)p.textContent='ทุกวัน';else if(ds.length===1)p.textContent=thai(ds[0]);else p.textContent=`เลือก ${ds.length} วัน: ${thai(ds[0])} - ${thai(ds[ds.length-1])}`}const pb=$('#psTickBtn289');if(pb){const ps=selectedPs();pb.textContent=ps.length?`PS: ${ps.length===1?ps[0]:ps.length+' คน'} ▼`:'PS: ทั้งหมด ▼'}window.DOIT_APP_SCOPE=getScope()}
function thai(s){const p=T(s).split('-');return p.length===3?`${p[2]}/${p[1]}/${p[0]}`:s}
function esc(s){return T(s).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]))}
function ensureModalCss(){if($('#manualModal290Css'))return;const st=document.createElement('style');st.id='manualModal290Css';st.textContent='.manualOverlay290{position:fixed;inset:0;background:rgba(15,23,42,.55);z-index:180;display:none;align-items:center;justify-content:center;padding:14px}.manualOverlay290.on{display:flex}.manualSheet290{width:min(94vw,560px);background:#fff;border-radius:18px;box-shadow:0 24px 80px rgba(0,0,0,.38);overflow:hidden}.manualHead290{background:#087b34;color:#fff;padding:14px 16px;font-weight:950;display:flex;justify-content:space-between;align-items:center}.manualBody290{padding:14px;display:grid;gap:10px}.manualBody290 label{font-size:12px;font-weight:950;color:#374151}.manualBody290 input{width:100%;height:42px;border:1px solid #cbd5e1;border-radius:10px;padding:0 10px;font-weight:900}.manualFoot290{display:grid;grid-template-columns:1fr 1fr;gap:10px;padding:12px;border-top:1px solid #e5e7eb}.manualFoot290 button{height:44px;border-radius:10px;font-weight:950}.manualCancel290{background:#fff;border:1px solid #d1d5db;color:#4b5563}.manualSave290{background:#087b34;border:0;color:#fff}';document.head.appendChild(st)}
function openManual(){const sc=getScope();if(!sc.receiver){alert('กรุณาเลือกร้านจริงก่อนเพิ่มสินค้านอก DOIT');return}ensureModalCss();let ov=$('#manualOverlay290');if(!ov){ov=document.createElement('div');ov.id='manualOverlay290';ov.className='manualOverlay290';ov.innerHTML=`<div class="manualSheet290"><div class="manualHead290"><span>เพิ่มสินค้านอก DOIT</span><button class="manualCancel290" type="button">ปิด</button></div><div class="manualBody290"><div><label>ร้านจริง</label><input id="manualStore290" readonly></div><div><label>ชื่อสินค้า/รายการ *</label><input id="manualName290" placeholder="ชื่อสินค้า"></div><div><label>จำนวนส่ง *</label><input id="manualQty290" type="number" step="1" min="1" value="1"></div><div><label>ราคา/หน่วย</label><input id="manualUnit290" type="number" step="0.01" min="0" value="0"></div><div><label>รหัส SKU ถ้ามี</label><input id="manualCode290" placeholder="ไม่บังคับ"></div><div><label>กลุ่ม/แบรนด์</label><input id="manualBrand290" value="เพิ่มเอง"></div></div><div class="manualFoot290"><button class="manualCancel290" type="button">ยกเลิก</button><button class="manualSave290" type="button">บันทึก</button></div></div>`;document.body.appendChild(ov);ov.addEventListener('click',e=>{if(e.target===ov||e.target.classList.contains('manualCancel290'))ov.classList.remove('on')});ov.querySelector('.manualSave290').onclick=saveManualModal}
$('#manualStore290').value=sc.receiver;$('#manualName290').value='';$('#manualQty290').value='1';$('#manualUnit290').value='0';$('#manualCode290').value='';$('#manualBrand290').value='เพิ่มเอง';ov.classList.add('on');setTimeout(()=>$('#manualName290')?.focus(),50)}
function saveManualModal(){const sc=getScope();const name=T($('#manualName290')?.value);const qty=N($('#manualQty290')?.value);const unit=N($('#manualUnit290')?.value);const code=T($('#manualCode290')?.value);const brand=T($('#manualBrand290')?.value)||'เพิ่มเอง';if(!sc.receiver)return alert('ไม่พบร้านจริง');if(!name)return alert('กรุณากรอกชื่อสินค้า');if(qty<=0)return alert('จำนวนต้องมากกว่า 0');const arr=read(manualKey(),[]);arr.push({id:Date.now(),store:sc.receiver,start:T($('#startDate')?.value),end:T($('#endDate')?.value),ps:sc.psKey||T($('#psSelect')?.value),dateKey:sc.dateKey,psKey:sc.psKey,name,qty,unit,code,brand,size:'',type:'MANUAL'});write(manualKey(),arr);$('#manualOverlay290')?.classList.remove('on');setMsg('เพิ่มสินค้านอก DOIT แล้ว');window.DOIT_JSON_APP?.rerender?.()}
function bindManual(){if(document.__manualModal290)return;document.__manualModal290=true;document.addEventListener('click',e=>{const btn=e.target?.closest?.('#manualAddBtn');if(btn){e.preventDefault();e.stopImmediatePropagation();openManual()}},true)}
function health(){return{version:APP_VERSION,patched,appKey:appKey(),rows:rawRows.length,scope:getScope(),manualKey:manualKey(),scripts:[...document.scripts].map(s=>s.getAttribute('src')).filter(Boolean).filter(s=>/doit|coordinator|fix|owner|drawer/i.test(s))}}
function expose(){window.DOIT_APP_COORDINATOR={version:APP_VERSION,getScope,health,openManual,manualKey,rerender:()=>window.DOIT_JSON_APP?.rerender?.()}}
function boot(){patchLoad();bindManual();expose();syncUi();let n=0;const tick=()=>{patchLoad();bindManual();expose();syncUi();if(++n<10)setTimeout(tick,600)};setTimeout(tick,300)}
document.addEventListener('DOMContentLoaded',boot);if(document.readyState!=='loading')boot();
})();